('update_fetch_task','drupal','a:7:{s:4:\"name\";s:6:\"drupal\";s:4:\"info\";a:6:{s:4:\"name\";s:13:\"Announcements\";s:7:\"version\";s:6:\"11.3.7\";s:7:\"package\";s:4:\"Core\";s:7:\"project\";s:6:\"drupal\";s:16:\"_info_file_ctime\";i:1776781230;s:9:\"datestamp\";i:0;}s:9:\"datestamp\";i:0;s:8:\"includes\";a:40:{s:18:\"announcements_feed\";s:13:\"Announcements\";s:14:\"automated_cron\";s:14:\"Automated Cron\";s:8:\"big_pipe\";s:7:\"BigPipe\";s:5:\"block\";s:5:\"Block\";s:13:\"block_content\";s:13:\"Block Content\";s:10:\"breakpoint\";s:10:\"Breakpoint\";s:9:\"ckeditor5\";s:10:\"CKEditor 5\";s:7:\"comment\";s:7:\"Comment\";s:6:\"config\";s:21:\"Configuration Manager\";s:10:\"contextual\";s:16:\"Contextual Links\";s:8:\"datetime\";s:8:\"Datetime\";s:5:\"dblog\";s:16:\"Database Logging\";s:18:\"dynamic_page_cache\";s:27:\"Internal Dynamic Page Cache\";s:6:\"editor\";s:11:\"Text Editor\";s:5:\"field\";s:5:\"Field\";s:8:\"field_ui\";s:8:\"Field UI\";s:4:\"file\";s:4:\"File\";s:6:\"filter\";s:6:\"Filter\";s:4:\"help\";s:4:\"Help\";s:7:\"history\";s:7:\"History\";s:5:\"image\";s:5:\"Image\";s:4:\"link\";s:4:\"Link\";s:17:\"menu_link_content\";s:17:\"Custom Menu Links\";s:7:\"menu_ui\";s:7:\"Menu UI\";s:5:\"mysql\";s:5:\"MySQL\";s:4:\"node\";s:4:\"Node\";s:7:\"options\";s:7:\"Options\";s:10:\"page_cache\";s:19:\"Internal Page Cache\";s:4:\"path\";s:4:\"Path\";s:10:\"path_alias\";s:10:\"Path alias\";s:6:\"search\";s:6:\"Search\";s:8:\"shortcut\";s:8:\"Shortcut\";s:6:\"system\";s:6:\"System\";s:8:\"taxonomy\";s:8:\"Taxonomy\";s:4:\"text\";s:4:\"Text\";s:7:\"toolbar\";s:7:\"Toolbar\";s:6:\"update\";s:13:\"Update Status\";s:4:\"user\";s:4:\"User\";s:5:\"views\";s:5:\"Views\";s:8:\"views_ui\";s:8:\"Views UI\";}s:12:\"project_type\";s:4:\"core\";s:14:\"project_status\";b:1;s:8:\"disabled\";a:33:{s:3:\"ban\";s:3:\"Ban\";s:10:\"basic_auth\";s:25:\"HTTP Basic Authentication\";s:18:\"config_translation\";s:25:\"Configuration Translation\";s:7:\"contact\";s:7:\"Contact\";s:18:\"content_moderation\";s:18:\"Content Moderation\";s:19:\"content_translation\";s:19:\"Content Translation\";s:14:\"datetime_range\";s:14:\"Datetime Range\";s:12:\"field_layout\";s:12:\"Field Layout\";s:18:\"inline_form_errors\";s:18:\"Inline Form Errors\";s:7:\"jsonapi\";s:8:\"JSON:API\";s:8:\"language\";s:8:\"Language\";s:14:\"layout_builder\";s:14:\"Layout Builder\";s:38:\"layout_builder_expose_all_field_blocks\";s:38:\"Layout Builder Expose All Field Blocks\";s:16:\"layout_discovery\";s:16:\"Layout Discovery\";s:6:\"locale\";s:21:\"Interface Translation\";s:5:\"media\";s:5:\"Media\";s:13:\"media_library\";s:13:\"Media Library\";s:7:\"migrate\";s:7:\"Migrate\";s:14:\"migrate_drupal\";s:14:\"Migrate Drupal\";s:17:\"migrate_drupal_ui\";s:17:\"Migrate Drupal UI\";s:10:\"navigation\";s:10:\"Navigation\";s:5:\"pgsql\";s:10:\"PostgreSQL\";s:6:\"phpass\";s:22:\"Password Compatibility\";s:16:\"responsive_image\";s:16:\"Responsive Image\";s:4:\"rest\";s:20:\"RESTful Web Services\";s:13:\"serialization\";s:13:\"Serialization\";s:13:\"settings_tray\";s:13:\"Settings Tray\";s:6:\"sqlite\";s:6:\"SQLite\";s:6:\"syslog\";s:6:\"Syslog\";s:9:\"telephone\";s:9:\"Telephone\";s:9:\"workflows\";s:9:\"Workflows\";s:10:\"workspaces\";s:10:\"Workspaces\";s:13:\"workspaces_ui\";s:13:\"Workspaces UI\";}}');
